try {
  const allItems = $input.all();
  let totalItems = 0;
  let categories = {};
  let transactions = [];
  let totalDebit = 0;
  let totalCredit = 0;

  for (const item of allItems) {
    totalItems++;
    let category = (item.json.category || item.json.output || "Others").trim();
    let type = (item.json.Type || item.json.type || "").toLowerCase();

    if (!categories[category]) {
      categories[category] = { count: 0, total_value: 0 };
    }
    categories[category].count++;

    let valueRaw = item.json.Value ?? item.json.value ?? item.json.Valor ?? item.json.valor ?? 0;
    let value = parseFloat(valueRaw.toString().replace(/[R$\s]/g, "").replace(",", "."));
    if (isNaN(value)) value = 0;

    categories[category].total_value = Math.round((categories[category].total_value + value) * 100) / 100;

    // Accumulate debit/credit
    if (type === "credit") {
      totalCredit = Math.round((totalCredit + value) * 100) / 100;
    } else {
      totalDebit = Math.round((totalDebit + value) * 100) / 100;
    }

    transactions.push({
      category: category,
      description: item.json.Description || item.json.description || "",
      value: value,
      date: item.json.Date || item.json.date || "",
      type: item.json.Type || item.json.type || ""
    });
  }

  return {
    json: {
      total_transactions: totalItems,
      total_debit: totalDebit,
      total_credit: totalCredit,
      balance: Math.round((totalCredit - totalDebit) * 100) / 100,
      categories: categories,
      transactions: transactions
    }
  };

} catch (err) {
  return { json: { error: err.message } };
}

const input = $input.first().json;

// Strip markdown fences if AI misbehaves
let raw = (input.output || "{}").trim();
raw = raw
  .replace(/^```json\s*/i, "")
  .replace(/^```\s*/i, "")
  .replace(/```$/i, "")
  .trim();

let parsed = {};
try {
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = { conta: "Others", valor: 0, data: "" };
}

return {
  json: {
    category: parsed.conta || "Others",
    Value: parsed.valor || 0,
    Date: parsed.data || "",
    Description: parsed.description || input.Description || input.description || "",
    Type: parsed.type || ""
  }
};
